"""
Enhanced Multi-Model Workflow Engine with Observer Pattern and Dynamic Resource Management
Implements 1-80% dynamic range with agent delegation and intelligent observer review cycles
"""

import time
import asyncio
import threading
from typing import Dict, List, Optional, Tuple, Any, Union
from dataclasses import dataclass, asdict
from enum import Enum
from collections import defaultdict, deque
import json

class ResourceMode(Enum):
    """Enhanced resource allocation modes"""
    FAST = "fast"           # 1-30% VRAM, minimal agents, quick results
    AUTO = "auto"           # 1-80% dynamic, observer pattern with agents
    THINK = "think"         # 20-80% VRAM, maximum reasoning depth

class AgentRole(Enum):
    """Agent roles in the observer pattern"""
    WORKER = "worker"           # Performs specific tasks
    VALIDATOR = "validator"     # Validates worker outputs
    OBSERVER = "observer"       # Manages workflow and reviews all outputs
    SYNTHESIZER = "synthesizer" # Combines results into final output

class TaskComplexity(Enum):
    """Task complexity levels for dynamic resource allocation"""
    SIMPLE = "simple"       # 1-20% resources
    MEDIUM = "medium"       # 20-50% resources
    COMPLEX = "complex"     # 50-80% resources
    CRITICAL = "critical"   # 60-80% resources, highest priority

@dataclass
class AgentConfig:
    """Configuration for workflow agents"""
    role: AgentRole
    model_name: str
    vram_allocation_gb: float
    max_concurrent_tasks: int
    priority_level: int
    specializations: List[str]
    timeout_seconds: int = 30

@dataclass
class WorkflowTask:
    """Enhanced workflow task with observer pattern support"""
    task_id: str
    complexity: TaskComplexity
    agent_role: AgentRole
    model_tier: str
    prompt: str
    expected_output: str
    dependencies: List[str] = None
    validation_criteria: Dict[str, Any] = None
    observer_review_required: bool = True
    retry_count: int = 0
    max_retries: int = 2

@dataclass
class AgentOutput:
    """Output from workflow agent"""
    agent_id: str
    task_id: str
    response: str
    confidence: float
    execution_time: float
    resource_usage: Dict[str, float]
    validation_score: float = 0.0
    observer_feedback: str = ""
    requires_refinement: bool = False

class AdaptiveResourceManager:
    """Manages dynamic resource allocation with 1-80% range"""

    def __init__(self, total_vram_gb: float):
        self.total_vram_gb = total_vram_gb
        self.active_allocations = {}
        self.current_usage = 0.0
        self.resource_history = deque(maxlen=100)

    def calculate_dynamic_allocation(self, mode: ResourceMode, task_complexity: TaskComplexity,
                                   active_agents: int = 1) -> Dict[str, float]:
        """Calculate dynamic resource allocation based on context"""

        # Base resource ranges by mode
        mode_ranges = {
            ResourceMode.FAST: {'min': 0.01, 'max': 0.30, 'observer_ratio': 0.2},
            ResourceMode.AUTO: {'min': 0.01, 'max': 0.80, 'observer_ratio': 0.4},
            ResourceMode.THINK: {'min': 0.20, 'max': 0.80, 'observer_ratio': 0.3}
        }

        # Complexity multipliers
        complexity_mult = {
            TaskComplexity.SIMPLE: 0.25,
            TaskComplexity.MEDIUM: 0.50,
            TaskComplexity.COMPLEX: 0.80,
            TaskComplexity.CRITICAL: 0.95
        }

        range_config = mode_ranges[mode]
        complexity_factor = complexity_mult[task_complexity]

        # Calculate target allocation
        vram_range = range_config['max'] - range_config['min']
        target_allocation = range_config['min'] + (vram_range * complexity_factor)

        # Distribute between agents and observer
        if mode == ResourceMode.AUTO:
            # Special auto mode: delegate 40% to agents, 40% to observer, 20% reserve
            agent_allocation = target_allocation * 0.4
            observer_allocation = target_allocation * 0.4
            reserve_allocation = target_allocation * 0.2
        else:
            observer_ratio = range_config['observer_ratio']
            observer_allocation = target_allocation * observer_ratio
            agent_allocation = (target_allocation - observer_allocation) / max(1, active_agents)
            reserve_allocation = 0.1

        return {
            'total_target': target_allocation,
            'agent_vram_ratio': agent_allocation,
            'observer_vram_ratio': observer_allocation,
            'reserve_ratio': reserve_allocation,
            'agent_vram_gb': agent_allocation * self.total_vram_gb,
            'observer_vram_gb': observer_allocation * self.total_vram_gb,
            'max_concurrent_agents': max(1, min(4, int(agent_allocation * 10)))
        }

class WorkflowObserver:
    """Intelligent observer that manages agents and reviews outputs"""

    def __init__(self, config: Dict[str, Any], resource_manager: AdaptiveResourceManager):
        self.config = config
        self.resource_manager = resource_manager
        self.active_agents = {}
        self.completed_tasks = []
        self.refinement_queue = deque()

        # Observer state
        self.observer_model = None
        self.observation_interval = 0.5  # seconds between agent checks
        self.reviewing = False

    async def manage_workflow(self, tasks: List[WorkflowTask], mode: ResourceMode) -> Dict[str, Any]:
        """Main workflow management with observer pattern"""

        print(f"🎯 Observer: Starting workflow management in {mode.value} mode")

        # Analyze task complexity distribution
        complexity_analysis = self._analyze_task_complexity(tasks)

        # Calculate resource allocation
        resource_allocation = self.resource_manager.calculate_dynamic_allocation(
            mode, complexity_analysis['dominant_complexity'], len(tasks)
        )

        print(f"📊 Resource Allocation:")
        print(f"   Agent VRAM: {resource_allocation['agent_vram_gb']:.2f}GB")
        print(f"   Observer VRAM: {resource_allocation['observer_vram_gb']:.2f}GB")
        print(f"   Max Concurrent: {resource_allocation['max_concurrent_agents']}")

        # Execute workflow based on mode
        if mode == ResourceMode.AUTO:
            return await self._execute_auto_mode_workflow(tasks, resource_allocation)
        elif mode == ResourceMode.FAST:
            return await self._execute_fast_mode_workflow(tasks, resource_allocation)
        else:  # THINK mode
            return await self._execute_think_mode_workflow(tasks, resource_allocation)

    def _analyze_task_complexity(self, tasks: List[WorkflowTask]) -> Dict[str, Any]:
        """Analyze the complexity distribution of tasks"""
        complexity_counts = defaultdict(int)
        for task in tasks:
            complexity_counts[task.complexity] += 1

        # Find dominant complexity
        dominant = max(complexity_counts.items(), key=lambda x: x[1])[0]

        return {
            'total_tasks': len(tasks),
            'complexity_distribution': dict(complexity_counts),
            'dominant_complexity': dominant,
            'requires_heavy_reasoning': any(t.complexity in [TaskComplexity.COMPLEX, TaskComplexity.CRITICAL] for t in tasks)
        }

    async def _execute_auto_mode_workflow(self, tasks: List[WorkflowTask],
                                        resource_allocation: Dict[str, float]) -> Dict[str, Any]:
        """Execute auto mode with dynamic agent-observer pattern"""

        print("🤖 Auto Mode: Dynamic agent delegation with observer review")

        # Phase 1: Deploy lightweight agents for initial processing
        agent_outputs = []
        concurrent_limit = resource_allocation['max_concurrent_agents']

        # Create agent batches based on resource limits
        task_batches = self._create_task_batches(tasks, concurrent_limit)

        for batch_idx, task_batch in enumerate(task_batches):
            print(f"\n📋 Processing batch {batch_idx + 1}/{len(task_batches)}")

            # Run agents concurrently within resource limits
            batch_results = await self._run_agent_batch(task_batch, resource_allocation)
            agent_outputs.extend(batch_results)

            # Observer review after each batch (except simple tasks)
            if any(task.complexity != TaskComplexity.SIMPLE for task in task_batch):
                print("🔍 Observer: Reviewing batch outputs...")
                reviewed_outputs = await self._observer_review_batch(batch_results, resource_allocation)

                # Trigger refinement if needed
                refinement_needed = [out for out in reviewed_outputs if out.requires_refinement]
                if refinement_needed:
                    print(f"🔄 Observer: {len(refinement_needed)} outputs need refinement")
                    refined_outputs = await self._refine_outputs(refinement_needed, resource_allocation)
                    agent_outputs.extend(refined_outputs)

        # Phase 2: Final synthesis by observer
        print("\n🎯 Observer: Synthesizing final output...")
        final_result = await self._synthesize_final_output(agent_outputs, resource_allocation)

        return {
            'mode': 'auto',
            'agent_outputs': len(agent_outputs),
            'total_resource_usage': self._calculate_total_usage(agent_outputs),
            'final_result': final_result,
            'workflow_efficiency': self._calculate_efficiency(agent_outputs),
            'observer_interventions': len([out for out in agent_outputs if out.requires_refinement])
        }

    def _create_task_batches(self, tasks: List[WorkflowTask], concurrent_limit: int) -> List[List[WorkflowTask]]:
        """Create task batches respecting concurrency limits and dependencies"""
        batches = []
        current_batch = []
        current_vram = 0.0

        # Sort tasks by priority (critical first, simple last)
        priority_order = {TaskComplexity.CRITICAL: 4, TaskComplexity.COMPLEX: 3,
                         TaskComplexity.MEDIUM: 2, TaskComplexity.SIMPLE: 1}
        sorted_tasks = sorted(tasks, key=lambda t: priority_order[t.complexity], reverse=True)

        for task in sorted_tasks:
            # Estimate VRAM needed for this task
            task_vram = self._estimate_task_vram(task)

            # Check if we can add this task to current batch
            if (len(current_batch) < concurrent_limit and
                current_vram + task_vram <= 0.6):  # 60% max per batch
                current_batch.append(task)
                current_vram += task_vram
            else:
                # Start new batch
                if current_batch:
                    batches.append(current_batch)
                current_batch = [task]
                current_vram = task_vram

        if current_batch:
            batches.append(current_batch)

        return batches

    def _estimate_task_vram(self, task: WorkflowTask) -> float:
        """Estimate VRAM requirements for a task"""
        base_requirements = {
            TaskComplexity.SIMPLE: 0.05,
            TaskComplexity.MEDIUM: 0.15,
            TaskComplexity.COMPLEX: 0.30,
            TaskComplexity.CRITICAL: 0.40
        }
        return base_requirements.get(task.complexity, 0.15)

    async def _run_agent_batch(self, tasks: List[WorkflowTask],
                             resource_allocation: Dict[str, float]) -> List[AgentOutput]:
        """Run a batch of tasks using appropriate agents"""
        batch_outputs = []

        # Simulate concurrent agent execution
        for task in tasks:
            print(f"   🤖 Agent processing: {task.task_id} ({task.complexity.value})")

            # Simulate agent work
            start_time = time.time()
            await asyncio.sleep(0.1)  # Simulate processing time

            # Generate mock output
            output = AgentOutput(
                agent_id=f"agent_{task.agent_role.value}",
                task_id=task.task_id,
                response=f"Processed {task.task_id} with {task.complexity.value} complexity",
                confidence=0.7 + (0.3 * (task.complexity == TaskComplexity.SIMPLE)),
                execution_time=time.time() - start_time,
                resource_usage={'vram_gb': self._estimate_task_vram(task)},
                validation_score=0.8
            )

            batch_outputs.append(output)

        return batch_outputs

    async def _observer_review_batch(self, outputs: List[AgentOutput],
                                   resource_allocation: Dict[str, float]) -> List[AgentOutput]:
        """Observer reviews agent outputs and provides feedback"""

        reviewed_outputs = []

        for output in outputs:
            # Observer analysis
            confidence_threshold = 0.75
            validation_threshold = 0.70

            # Determine if refinement needed
            needs_refinement = (
                output.confidence < confidence_threshold or
                output.validation_score < validation_threshold
            )

            # Generate observer feedback
            if needs_refinement:
                output.requires_refinement = True
                output.observer_feedback = f"Low confidence ({output.confidence:.2f}), needs refinement"
                print(f"   🔍 Observer: {output.task_id} flagged for refinement")
            else:
                output.observer_feedback = "Output meets quality standards"

            reviewed_outputs.append(output)

        return reviewed_outputs

    async def _refine_outputs(self, outputs: List[AgentOutput],
                            resource_allocation: Dict[str, float]) -> List[AgentOutput]:
        """Refine outputs that didn't pass observer review"""

        refined_outputs = []

        for output in outputs:
            print(f"   🔄 Refining: {output.task_id}")

            # Use higher-tier model for refinement
            start_time = time.time()
            await asyncio.sleep(0.15)  # Simulate refinement processing

            refined_output = AgentOutput(
                agent_id=f"refiner_{output.agent_id}",
                task_id=f"{output.task_id}_refined",
                response=f"Refined: {output.response}",
                confidence=min(0.95, output.confidence + 0.2),
                execution_time=time.time() - start_time,
                resource_usage={'vram_gb': output.resource_usage['vram_gb'] * 1.5},
                validation_score=min(0.95, output.validation_score + 0.15),
                observer_feedback="Refinement completed"
            )

            refined_outputs.append(refined_output)

        return refined_outputs

    async def _synthesize_final_output(self, all_outputs: List[AgentOutput],
                                     resource_allocation: Dict[str, float]) -> Dict[str, Any]:
        """Observer synthesizes all agent outputs into final result"""

        print("   🎯 Synthesizing final output from all agent results...")

        # Simulate synthesis processing
        await asyncio.sleep(0.2)

        if not all_outputs:
            return {'synthesized_response': 'No outputs', 'overall_confidence': 0.0, 'overall_validation': 0.0,
                    'component_count': 0, 'refinement_iterations': 0, 'resource_efficiency': 0.0}

        total_confidence = sum(out.confidence for out in all_outputs) / len(all_outputs)
        total_validation = sum(out.validation_score for out in all_outputs) / len(all_outputs)

        # Generate actual response instead of placeholder text
        try:
            # Use a simple fallback for now - should call actual model
            synthesized_response = f"Response to: {user_request}"
        except Exception:
            synthesized_response = f"Combined output from {len(all_outputs)} agent results"

        synthesis_result = {
            'synthesized_response': synthesized_response,
            'overall_confidence': total_confidence,
            'overall_validation': total_validation,
            'component_count': len(all_outputs),
            'refinement_iterations': len([out for out in all_outputs if 'refined' in out.task_id]),
            'resource_efficiency': resource_allocation['agent_vram_gb'] + resource_allocation['observer_vram_gb']
        }

        return synthesis_result

    async def _execute_fast_mode_workflow(self, tasks: List[WorkflowTask],
                                        resource_allocation: Dict[str, float]) -> Dict[str, Any]:
        """Fast mode: minimal resources, quick results"""
        print("⚡ Fast Mode: Minimal resource usage, quick execution")

        # Use only lightweight models, minimal observer intervention
        outputs = await self._run_agent_batch(tasks[:2], resource_allocation)  # Limit tasks

        return {
            'mode': 'fast',
            'agent_outputs': len(outputs),
            'final_result': {'response': 'Fast mode result', 'confidence': 0.75}
        }

    async def _execute_think_mode_workflow(self, tasks: List[WorkflowTask],
                                         resource_allocation: Dict[str, float]) -> Dict[str, Any]:
        """Think mode: maximum reasoning depth"""
        print("🧠 Think Mode: Maximum reasoning depth and analysis")

        # Use all available resources, multiple review cycles
        all_outputs = []
        for task in tasks:
            outputs = await self._run_agent_batch([task], resource_allocation)
            reviewed = await self._observer_review_batch(outputs, resource_allocation)
            all_outputs.extend(reviewed)

        final_result = await self._synthesize_final_output(all_outputs, resource_allocation)

        return {
            'mode': 'think',
            'agent_outputs': len(all_outputs),
            'final_result': final_result
        }

    def _calculate_total_usage(self, outputs: List[AgentOutput]) -> Dict[str, float]:
        """Calculate total resource usage from outputs"""
        total_vram = sum(out.resource_usage.get('vram_gb', 0) for out in outputs)
        total_time = sum(out.execution_time for out in outputs)

        return {
            'total_vram_gb': total_vram,
            'total_time_seconds': total_time,
            'average_confidence': sum(out.confidence for out in outputs) / len(outputs)
        }

    def _calculate_efficiency(self, outputs: List[AgentOutput]) -> float:
        """Calculate workflow efficiency score"""
        if not outputs:
            return 0.0

        avg_confidence = sum(out.confidence for out in outputs) / len(outputs)
        avg_validation = sum(out.validation_score for out in outputs) / len(outputs)

        return (avg_confidence + avg_validation) / 2

def _resolve_vram(quant_manager=None, scorer=None) -> float:
    """Safely resolve VRAM with multiple fallbacks"""
    # Prefer scorer.gpu_memory when available
    if scorer is not None and hasattr(scorer, "gpu_memory"):
        try:
            return float(getattr(scorer, "gpu_memory") or 0.0)
        except Exception:
            pass

    # Try quant_manager
    if quant_manager is not None:
        vram = getattr(quant_manager, "gpu_memory", None)
        if vram is None and hasattr(quant_manager, "detect_vram_gb"):
            try:
                vram = quant_manager.detect_vram_gb()
            except Exception:
                vram = 0.0
        return float(vram or 0.0)

    return 0.0

class AdaptiveWorkflowEngine:
    """Main engine integrating all components"""

    def __init__(self, quant_manager, config, scorer=None):
        self.quant_manager = quant_manager
        self.config = config
        self.scorer = scorer

        # Use safe VRAM resolution with scorer preference
        vram = _resolve_vram(self.quant_manager, self.scorer)
        self.resource_manager = AdaptiveResourceManager(vram)
        self.observer = WorkflowObserver(config, self.resource_manager)

    async def execute_workflow(self, user_request: str, mode: str = "auto") -> Dict[str, Any]:
        """Execute adaptive workflow with observer pattern (with timeout guard)"""

        # Parse mode
        resource_mode = ResourceMode(mode.lower())

        # Analyze request and create tasks
        tasks = self._create_tasks_from_request(user_request, resource_mode)

        # Execute workflow without hard timeout; rely on user cancel/progress
        result = await self.observer.manage_workflow(tasks, resource_mode)
        return result

    def _create_tasks_from_request(self, user_request: str, mode: ResourceMode) -> List[WorkflowTask]:
        """Create workflow tasks from user request"""

        # Analyze request complexity
        if any(keyword in user_request.lower() for keyword in ['analyze', 'complex', 'deep']):
            complexity = TaskComplexity.COMPLEX
        elif any(keyword in user_request.lower() for keyword in ['quick', 'simple', 'fast']):
            complexity = TaskComplexity.SIMPLE
        else:
            complexity = TaskComplexity.MEDIUM

        # Create sample tasks
        tasks = [
            WorkflowTask(
                task_id="parse_request",
                complexity=TaskComplexity.SIMPLE,
                agent_role=AgentRole.WORKER,
                model_tier="ultra_light",
                prompt=f"Parse and understand: {user_request}",
                expected_output="structured_data"
            ),
            WorkflowTask(
                task_id="main_processing",
                complexity=complexity,
                agent_role=AgentRole.WORKER,
                model_tier="medium" if complexity == TaskComplexity.MEDIUM else "heavy",
                prompt=f"Process request: {user_request}",
                expected_output="detailed_response"
            ),
            WorkflowTask(
                task_id="validation",
                complexity=TaskComplexity.SIMPLE,
                agent_role=AgentRole.VALIDATOR,
                model_tier="light",
                prompt="Validate the processing results",
                expected_output="validation_report"
            )
        ]

        return tasks


